#include <stdio.h>

float calculate_transaction_fee(int gas_units_used, float gas_price_in_eth) {
 float total_transaction_fee = gas_units_used * gas_price_in_eth;
 return total_transaction_fee;
}

int main() {
 int gas_units_used = 10000;
 float gas_price_in_eth = 0.00002;
 printf("Total transaction fee: %f ETH\n", calculate_transaction_fee(gas_units_used, gas_price_in_eth));
 return 0;
}
